//! Decode a **PNG** to luminance scanlines and emit [`PleromaticFrame::noaa_apt_scanlines`] (bincode).
//!
//! Use when the PNG is (or should be shown as) **NOAA APT grayscale** in `aeon-monitor`
//! (`NOAA APT SCANLINE RECONSTRUCTION` banner, `apt_width` / `apt_height`),
//! instead of the generic **embedded-PNG** path (`png-embed-frame`).
//!
//! ```text
//! png-noaa-apt-frame INPUT.png [OUTPUT.frame] [--center-hz HZ]
//! ```
//! Default `OUTPUT.frame`: `noaa_apt.frame`

use distributed_inference::pleromatic_frame::{decode_png_to_grayscale_row_major, PleromaticFrame};

fn strip_flags(argv: &mut Vec<String>) -> Result<Option<u64>, String> {
    let mut center_hz: Option<u64> = None;
    let mut i = 0usize;
    while i < argv.len() {
        if argv[i] == "--center-hz" {
            let v = argv
                .get(i + 1)
                .ok_or_else(|| "--center-hz requires a value".to_string())?;
            let n: u64 = v
                .parse()
                .map_err(|_| format!("invalid --center-hz: {}", v))?;
            center_hz = Some(n);
            argv.remove(i);
            argv.remove(i);
            continue;
        }
        if argv[i].starts_with("--") {
            return Err(format!("unknown flag: {}", argv[i]));
        }
        i += 1;
    }
    Ok(center_hz)
}

fn main() -> Result<(), String> {
    let mut argv: Vec<String> = std::env::args().skip(1).collect();
    if argv.is_empty() {
        return Err(
            "png-noaa-apt-frame INPUT.png [OUTPUT.frame] [--center-hz HZ]\n\
             Decodes PNG → luma row-major bytes, writes NOAA APT `PleromaticFrame` for aeon-monitor."
                .to_string(),
        );
    }

    let center_hz = strip_flags(&mut argv)?;

    let input = argv
        .first()
        .cloned()
        .ok_or_else(|| "missing INPUT.png".to_string())?;
    let output = argv
        .get(1)
        .cloned()
        .unwrap_or_else(|| "noaa_apt.frame".to_string());

    let png = std::fs::read(&input).map_err(|e| e.to_string())?;
    let (row_major, apt_w, apt_h) = decode_png_to_grayscale_row_major(&png)?;
    if row_major.len() != apt_w * apt_h {
        return Err("internal shape mismatch after PNG decode".into());
    }

    let source_id = std::path::Path::new(&input)
        .file_name()
        .and_then(|s| s.to_str())
        .unwrap_or("noaa-from-png")
        .to_string();

    let frame = PleromaticFrame::noaa_apt_scanlines(source_id, apt_w, apt_h, row_major, center_hz);
    let blob = bincode::serialize(&frame).map_err(|e| e.to_string())?;
    std::fs::write(&output, blob).map_err(|e| e.to_string())?;
    Ok(())
}
